function App() {
  const [urls, setUrls] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(0);

  return (
    <div style={{ textAlign: "center" }}>
      <h1>🌐 URL Navigator</h1>

      <Upload setUrls={setUrls} />

      {urls.length > 0 && (
        <div>
          <iframe
            src={urls[currentIndex]}
            title="viewer"
            width="80%"
            height="400px"
          />

          <div>
            <button
              onClick={() =>
                setCurrentIndex((prev) => Math.max(prev - 1, 0))
              }
            >
              Previous
            </button>

            <button
              onClick={() =>
                setCurrentIndex((prev) =>
                  Math.min(prev + 1, urls.length - 1)
                )
              }
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
